Segment_ROI_API_v10 参数说明 > 11. threshold analyze_particles + ROI 渲染示例

```json
{
  "sessionId": "sess001",
  "segmentationMethod": "threshold",
  "operation": "analyze_particles",
  "inputResources": {
    "binaryImageResourceUuid": "threshold_binary.png"
  },
  "params": {
    "analyzeParticlesParams": {
      "sizeMin": 20,
      "sizeMax": 2000,
      "circularityMin": 0.2,
      "circularityMax": 1.0,
      "excludeOnEdges": false,
      "includeHoles": false
    }
  },
  "roiRenderParams": {
    "enabled": true,
    "renderImageResourceUuid": "original_or_pseudo_image.png",
    "renderContour": true,
    "renderMaskOverlay": false,
    "contourColor": "#FFFF00",
    "contourWidthPixels": 2
  },
  "outputOptions": {
    "returnRoiZip": true,
    "returnRoiRender": true,
    "returnRenderedImageStoredFile": true,
    "returnRoiMaskStoredFile": true
  }
}
```

Segment_ROI_API_v10 参数说明 > 12. cellpose + ROI 渲染示例

```json
{
  "sessionId": "sess001",
  "segmentationMethod": "cellpose",
  "operation": "run_segmentation",
  "inputResources": {
    "sourceImageResourceUuid": "dapi_ch2.png"
  },
  "params": {
    "cellposeParams": {
      "model": "zhijing_if_nuclei",
      "diameter": 18,
      "flowThreshold": {"min": 0.2, "max": 0.8},
      "cellprobThreshold": {"min": -2, "max": 1}
    }
  },
  "roiRenderParams": {
    "enabled": true,
    "renderImageResourceUuid": "dapi_ch2_pseudo.png",
    "renderContour": true,
    "contourColor": "#FFFF00",
    "contourWidthPixels": 2
  },
  "outputOptions": {
    "returnRoiZip": true,
    "returnRoiRender": true
  }
}
```

